	}

	if (v2_signing_blocks != 1) {
		pr_err("Unexpected v2 signature count: %d\n",
		       v2_signing_blocks);
		v2_signing_valid = false;
	}

	if (v2_signing_valid) {
		int has_v1_signing = has_v1_signature_file(fp);
		if (has_v1_signing) {
			pr_err("Unexpected v1 signature scheme found!\n");
			filp_close(fp, 0);
